local Config <const> = {}

-- ============================================================================
-- ⚠  MOST OF THIS CONFIG IS EDITABLE LIVE IN-GAME — DO NOT EDIT THIS FILE
-- ----------------------------------------------------------------------------
-- The following sections are persisted in the `lo_settings` SQL table and
-- edited via the admin panel (Configuration serveur tab):
--   Paycheck, Logs, DefaultGrades, Features, Performance,
--   PermissionGroup, ButtonPermissions, EntityTypes, InteractionTypes,
--   Actions
--
-- Any change you make in-game overrides the values below on boot.
-- Edit this file ONLY to set the initial defaults before the first boot.
-- ============================================================================

-- ============================================================================
-- ICON NOTE
-- ----------------------------------------------------------------------------
-- All `icon = 'fa-solid fa-...'` fields below are FontAwesome classes used by
-- the ox_lib menu provider ONLY. The VORP menu does not render icons — if you
-- run the script without ox_lib, icons are ignored silently.
-- ============================================================================

-- ============================================================================
-- LANGUAGE NOTE
-- ----------------------------------------------------------------------------
-- Built-in defaults that are shown to players/admins use `labelKey` entries
-- resolved from `locales/*.json`. The plain `label` fields remain as fallback
-- values and as examples for custom entries you add yourself.
-- Add your own <lang>.json file and pick the active language via Config.Lang
-- below. The locale loader is built into the script (no ox_lib dependency).
-- Source code comments are kept in English so the script stays readable for
-- anyone maintaining or reselling it internationally.
-- ============================================================================

-- ============================================================================
-- GENERAL
-- ============================================================================
Config.Debug = false
Config.LogLevel = 'info'                             -- Console log level: 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'off'. Lower = more output. Change live: /jc_loglevel <level> (admin). When chasing a player bug, set 'debug' or 'trace', reproduce, read the log.
Config.VersionCheck = {
    enabled   = true,                                                   -- Print a notice on server start if a newer version exists on GitHub
    repo      = 'DeVerino-DVR/lo_jobscreator-version',                  -- Public repo holding version.txt + patchnote.txt (no source code). Format 'user/repo'. Leave '' to disable.
    branch    = 'main',
    updateUrl = 'https://portal.cfx.re/assets/granted-assets',          -- Where buyers re-download an updated copy (the cfx granted assets page)
}
Config.Command = 'jobcreator'                       -- Command to open the admin menu
Config.ActionMenuKey = 'F7'                          -- Key to open the personal action menu
-- Dispatch open key: NOT bound by lo_jobscreator. ox_lib (when present)
-- registers 'dispatch' (default U) and 'cursorDispatch' (default J) via
-- lo_keysMapper. Players rebind them in-game via `/keysmenu`. Buyers running
-- the dependency-free default menu can wire their own key in
-- modules/editable/client.lua → RegisterDispatchMenuKey.
Config.WitnessSonarOffset = 50                       -- Random GPS offset (m) so cops don't see the exact spot
