-- ============================================================================
-- ENTITY PLACEMENT MODE (peds, props, blips, markers, vehicles)
-- ----------------------------------------------------------------------------
-- 'raycast' (default) — point with the mouse, raycast hit becomes the position.
--                       Rotate with scroll wheel, validate with left click.
-- 'gizmo'             — entity is spawned in front of the player and a 3D
--                       gizmo overlay lets you drag/rotate it precisely.
--                       Toggle translate/rotate with [W]/[R], finish with
--                       [BACKSPACE]. Requires jo_libs (NUI multiplexer).
--
-- Players with the "preferences" permission can override this at runtime via
-- the in-game Settings panel; the value below is just the server-wide default.
-- ============================================================================
Config.PlacementMode = 'raycast' -- 'raycast' | 'gizmo'

-- ============================================================================
-- ITEM IMAGE UPLOAD PATH (for the "Download item image" button in the panel)
-- ============================================================================
--
-- IMPORTANT FOR SERVER OWNERS:
--   On RedM, Lua's io.open cannot reliably write across resources when the
--   server folder contains [bracketed] segments (e.g. resources/[inventory]/...)
--   or sits on a Windows mount with restricted permissions. If the auto-
--   detected path doesn't work for your install, set the ABSOLUTE path to
--   your inventory's items folder here. MUST end with a trailing slash.
--
-- Examples:
--   Windows : Config.ItemImagePath = 'C:/RedM/MyServer/resources/[inventory]/vorp_inventory/html/img/items/'
--   Linux   : Config.ItemImagePath = '/home/redm/server/resources/[inventory]/vorp_inventory/html/img/items/'
--   Other inventory : Config.ItemImagePath = '/path/to/my_inventory/web/images/'
--
-- Leave it as nil to let the resource auto-detect (works on most setups).
-- Config.ItemImagePath = 'C:/RedM/LastCountry/resources/[inventory]/vorp_inventory/html/img/items/' -- machine
Config.ItemImagePath = 'D:/LastCountryV7_VORP/resources/[inventory]/vorp_inventory/html/img/items/' -- dev
-- ============================================================================
-- FRAMEWORK BRIDGE  —  VORP only.
-- ----------------------------------------------------------------------------
-- This release supports VORP (vorp_core + vorp_inventory). When vorp_core isn't
-- running the bridge degrades to "standalone" (statebag-based, minimal).
-- Want another framework? modules/editable/framework.lua is yours to rewrite —
-- everything the script touches goes through the Framework_* functions there.
-- ============================================================================
Config.Framework = {
    force = 'auto', -- 'auto' | 'vorp' | 'standalone'

    -- Optional: if you run a separate job-management resource that exposes
    -- upsert/delete exports, declare them here and panel-created jobs/gangs get
    -- pushed to it too. Leave the table out entirely to skip (VORP has no
    -- central job registry — jobs are just strings on the character).
    -- entityExports = {
    --     vorp = { resource = 'my_jobs', upsertJob = 'AddJob', upsertGang = 'AddGang',
    --              deleteJob = 'RemoveJob', deleteGang = 'RemoveGang' },
    -- },

    -- Clothing store / wardrobe events fired when a player uses a clothing_store /
    -- clothing_wardrobe interaction. Empty 'openStore'/'openWardrobe' disables it.
    -- For full control (exports, conditional logic) override CustomOpenClothingStore /
    -- CustomOpenWardrobe in modules/editable/server.lua instead.
    clothing = {
        -- Default: jo_clothingstore (Jump-On-Studios). Common alternatives:
        --   vorp_clothing : 'vorp_clothing:OpenMenu'
        --   bcc-clothes   : 'bcc-clothes:openClothingStore'
        openStore    = 'jo_clothingstore:openStore',
        openWardrobe = 'jo_clothingstore:openWardrobe',
        storeArgs    = { useOutfitMenu = true, needInstance = false },
        wardrobeArg  = false,
        preferExport = true,
        exportResource = 'jo_clothingstore',
    },

    -- Server → client toast event used by NotifyClient. Leave nil for auto
    -- (ox_lib:notify if ox_lib is installed, otherwise vorp:TipBottom).
    notify = {
        vorp = nil, -- e.g. 'vorp:TipBottom' or 'ox_lib:notify'
    },
}

