-- Menu/Input options: 'ox_lib', 'vorp' or 'jo_libs'
-- Interaction options: 'target' (ox_target) or 'prompt' (VORP prompts)
-- NOTE: For 'jo_libs', ensure `jo_libs` is installed and `@jo_libs/init.lua`
-- is uncommented in fxmanifest.lua (shared_scripts).
-- ============================================================================
Config.AllowInGamePreferences = true
-- Menu options   : 'auto' | 'ox_lib' | 'vorp' | 'jo_libs' | 'native'
-- Input options  : 'auto' | 'ox_lib' | 'vorp' | 'jo_libs' | 'native'
-- Progress options: 'auto' | 'ox_lib' | 'vorp' | 'native'
-- 'auto'   = pick the first available (ox_lib -> jo_libs -> vorp -> native)
