-- ============================================================================
-- PAYCHECK
-- Configure which exports to use for banking and company accounts
-- Set to false to disable a specific integration
-- ============================================================================
Config.Paycheck = {
    enabled = true,
    interval = 1000 * 60 * 30,
    log = true,

    -- ── HOW THE SALARY REACHES THE PLAYER ──────────────────────────────────
    -- By default the salary is added to the player IN CASH (dollars on the
    -- character) so the script works out of the box with nothing else installed.
    --
    -- Want it deposited into a BANK instead? Set `banking.enabled = true` and
    -- point `resource` / `fn` at your banking resource's "add money to account"
    -- export (signature: exports[resource]:fn(source, amount)). Example:
    --   banking = { enabled = true, resource = 'vorp_banking', fn = 'addBankMoney' }
    --
    -- ⚠ `lo_banking` below is a PRIVATE resource — it is NOT sold and NOT bundled
    --   with this script. The entry is just the value used on the original
    --   author's production server; it stays inert as long as `enabled = false`.
    --   On any other server, leave `enabled = false` (cash) or set it to your own
    --   banking resource.
    banking = {
        enabled  = true,           -- false = pay in cash | true = deposit via the export below
        resource = 'lo_banking',    -- your banking resource name (only used when enabled = true)
        fn       = 'addBankMoney',  -- export on it: exports[resource]:fn(source, amount)
    },

    -- ── COMPANY / GANG ACCOUNTS ────────────────────────────────────────────
    -- Government-type jobs (see governmentTypes) and the 'unemployed' / 'citizen'
    -- defaults are paid by the state (the money comes from nowhere). EVERY OTHER
    -- job/gang is paid out of its boss/gang account, and the payout is skipped
    -- when that account is short. If you don't run a boss-menu / gang-menu
    -- resource exposing these exports, those salaries simply won't be paid until
    -- you wire one — or add those job types to `governmentTypes`. Pointing
    -- `resource` at something you don't have just makes the call a safe no-op.
    --   GetAccount  signature: exports[resource]:getAccountFn(jobName) -> number
    --   RemoveMoney signature: exports[resource]:removeMoneyFn(jobName, amount)
    bossAccount = {
        resource = 'lo_bossmenu',
        getAccountFn = 'GetAccount',
        removeMoneyFn = 'RemoveMoney',
    },
    gangAccount = {
        resource = 'lo_gangmenu',
        getAccountFn = 'GetAccount',
        removeMoneyFn = 'RemoveMoney',
    },

    -- Job types paid by the state (salary from nowhere, not a company account).
    governmentTypes = { 'leo', 'medic', 'gouv' },
}

-- ============================================================================
-- KEYBINDS (built-in RDR2 prompt letter + RedM control hash for cancel/complete)
-- ============================================================================
-- Each entry has a `prompt` (letter shown on the built-in RDR2 UiPrompt) AND a
-- `control` (RedM control hash used by IsControlJustPressed / IsControlJustReleased).
-- Keep them aligned so the on-screen prompt and the actual key match.
Config.Keys = {
    interact      = { prompt = 'G', control = 0x760A9C6F }, -- INPUT_CONTEXT (open interaction menu)
    cancelAction  = { prompt = 'X', control = 0x4CC0E2FE }, -- INPUT_FRONTEND_DELETE (cancel current action)
    phoneHangup   = { prompt = 'H', control = 0xF1301666 }, -- INPUT_CELLPHONE_CANCEL (hang up phone call)
    deliveryDone  = { prompt = 'L', control = 0xC7B5340A }, -- INPUT_MP_TEXT_CHAT_ALL (complete delivery)
}

-- Keys for the usable-item prompt loop (drink, eat, ...). Each entry maps a
-- locale key (used for the on-screen label) to a RedM control hash. Server
-- owners are encouraged to remap them here without touching the module code.
Config.UsableKeys = {
    use     = { labelKey = 'usable_prompt_use',     control = 0x27D1C284 }, -- INPUT_INTERACT_PICKUP
    health  = { labelKey = 'usable_prompt_health',  control = 0x760A9C6F }, -- INPUT_CONTEXT
    chug    = { labelKey = 'usable_prompt_chug',    control = 0x27D1C284 }, -- same key as `use`, different label
    stash   = { labelKey = 'usable_prompt_stash',   control = 0x7DA48D2A }, -- INPUT_FRONTEND_RB
    discard = { labelKey = 'usable_prompt_discard', control = 0x3B24C470 }, -- INPUT_FRONTEND_RT
}

